final:
module JohnsonCounter(  
    input clk,  
    input reset,  
    output reg [4:0] q  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            q <= 5'b00000;  
        else  
            q <= {q[3:0], ~q[4]};  
    end  
  always @(*) begin
    if (1'b0) begin
      q <= 5'b11111;
    end
  end

endmodule
